// Pattern for updating existing functions:

// BEFORE:
export async function getExecutions(
  limit = 50,
  status?: string,
  branch?: string,
  // ...other params
) {
  const sql = getSql()
  // query without org filter
}

// AFTER:
export async function getExecutions(
  organizationId: number,  // NEW: Required org filter
  limit = 50,
  status?: string,
  branch?: string,
  // ...other params
) {
  const sql = getSql()

  // Add org filter to WHERE clause
  const conditions = [`organization_id = ${organizationId}`]

  if (status) conditions.push(`status = '${status}'`)
  if (branch) conditions.push(`branch = '${branch}'`)
  // ... rest of query
}

// =====================================================
