/**
 * Create org-bound query functions.
 * Use this to avoid passing organizationId to every function.
 */
export function getQueriesForOrg(organizationId: number) {
  return {
    getExecutions: (limit?: number, status?: string, branch?: string, suite?: string) =>
      getExecutions(organizationId, limit, status, branch, suite),

    searchTests: (query: string, limit?: number) =>
      searchTests(organizationId, query, limit),

    getDashboardMetrics: (from?: string, to?: string) =>
      getDashboardMetrics(organizationId, from, to),

    // ... all other functions pre-bound with orgId
  }
}

// Usage in API routes:
const context = await getSessionContext()
const db = getQueriesForOrg(context.organizationId)
const executions = await db.getExecutions(50, "failed")

