// BEFORE (typical route):
import { authServer } from "@/lib/auth/server"
import { getExecutions } from "@/lib/db"

export async function GET(request: Request) {
  const session = await authServer.getSession()
  if (!session?.user?.email) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const executions = await getExecutions(50)
  return NextResponse.json({ executions })
}

// AFTER (with org context):
import { getSessionContext } from "@/lib/session-context"
import { getQueriesForOrg } from "@/lib/db"

export async function GET(request: Request) {
  const context = await getSessionContext()
  if (!context) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const db = getQueriesForOrg(context.organizationId)
  const executions = await db.getExecutions(50)

  return NextResponse.json({ executions })
}

security_check.pseudocode:
// For endpoints that fetch a single resource by ID:
export async function GET(
  request: Request,
  { params }: { params: { id: string } }
) {
  const context = await getSessionContext()
  if (!context) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const id = parseInt(params.id)
  const db = getQueriesForOrg(context.organizationId)

  // This query already filters by org, so if not found = either doesn't exist OR wrong org
  const execution = await db.getExecutionById(id)

  if (!execution) {
    return NextResponse.json({ error: "Not found" }, { status: 404 })
  }

  return NextResponse.json({ execution })
}

