import { getSql } from "./db"

export interface Organization {
  id: number
  name: string
  slug: string
  created_by: number | null
  created_at: string
  updated_at: string
}

export interface OrganizationMember {
  id: number
  organization_id: number
  user_id: number
  role: "owner" | "admin" | "viewer"
  joined_at: string
  // Joined fields
  user_email?: string
  user_name?: string
}

// =====================================================
// Organization CRUD
// =====================================================

export async function createOrganization(
  name: string,
  slug: string,
  createdBy: number
): Promise<Organization> {
  const sql = getSql()
  const [org] = await sql`
    INSERT INTO organizations (name, slug, created_by)
    VALUES (${name}, ${slug}, ${createdBy})
    RETURNING *
  `

  // Add creator as owner
  await sql`
    INSERT INTO organization_members (organization_id, user_id, role)
    VALUES (${org.id}, ${createdBy}, 'owner')
  `

  return org
}

export async function getOrganizationById(id: number): Promise<Organization | null> {
  const sql = getSql()
  const [org] = await sql`SELECT * FROM organizations WHERE id = ${id}`
  return org || null
}

export async function getOrganizationBySlug(slug: string): Promise<Organization | null> {
  const sql = getSql()
  const [org] = await sql`SELECT * FROM organizations WHERE slug = ${slug}`
  return org || null
}

export async function updateOrganization(
  id: number,
  updates: { name?: string; slug?: string }
): Promise<Organization | null> {
  const sql = getSql()
  const [org] = await sql`
    UPDATE organizations
    SET
      name = COALESCE(${updates.name}, name),
      slug = COALESCE(${updates.slug}, slug),
      updated_at = NOW()
    WHERE id = ${id}
    RETURNING *
  `
  return org || null
}

export async function deleteOrganization(id: number): Promise<boolean> {
  const sql = getSql()
  // Note: CASCADE will delete members, but test data needs handling
  const result = await sql`DELETE FROM organizations WHERE id = ${id}`
  return result.count > 0
}

// =====================================================
// Organization Members
// =====================================================

export async function getOrganizationMembers(orgId: number): Promise<OrganizationMember[]> {
  const sql = getSql()
  return sql`
    SELECT
      om.*,
      u.email as user_email
    FROM organization_members om
    JOIN dashboard_users u ON u.id = om.user_id
    WHERE om.organization_id = ${orgId}
    ORDER BY om.role, om.joined_at
  `
}

export async function addOrganizationMember(
  orgId: number,
  userId: number,
  role: "admin" | "viewer" = "viewer"
): Promise<OrganizationMember> {
  const sql = getSql()
  const [member] = await sql`
    INSERT INTO organization_members (organization_id, user_id, role)
    VALUES (${orgId}, ${userId}, ${role})
    RETURNING *
  `
  return member
}

export async function updateMemberRole(
  orgId: number,
  userId: number,
  newRole: "owner" | "admin" | "viewer"
): Promise<OrganizationMember | null> {
  const sql = getSql()
  const [member] = await sql`
    UPDATE organization_members
    SET role = ${newRole}
    WHERE organization_id = ${orgId} AND user_id = ${userId}
    RETURNING *
  `
  return member || null
}

export async function removeMember(orgId: number, userId: number): Promise<boolean> {
  const sql = getSql()
  const result = await sql`
    DELETE FROM organization_members
    WHERE organization_id = ${orgId} AND user_id = ${userId}
  `
  return result.count > 0
}

export async function getUserOrganizations(userId: number): Promise<Organization[]> {
  const sql = getSql()
  return sql`
    SELECT o.*, om.role as user_role
    FROM organizations o
    JOIN organization_members om ON om.organization_id = o.id
    WHERE om.user_id = ${userId}
    ORDER BY o.name
  `
}

// =====================================================
// Organization Invites
// =====================================================

export async function createOrgInvite(
  orgId: number,
  email: string,
  role: "admin" | "viewer",
  invitedBy: number
): Promise<{ id: number; email: string; role: string }> {
  const sql = getSql()
  // Use existing invites table with org context
  const [invite] = await sql`
    INSERT INTO invites (email, role, invited_by, org_id)
    VALUES (${email}, ${role}, ${invitedBy}, ${orgId})
    ON CONFLICT (email) DO UPDATE SET role = ${role}, org_id = ${orgId}
    RETURNING id, email, role
  `
  return invite
}

// Note: Need to add org_id column to invites table in migration

import { NextResponse } from "next/server"
import { getSessionContext, requireSystemAdmin } from "@/lib/session-context"
import { getUserOrganizations, createOrganization } from "@/lib/db-orgs"

// GET /api/organizations - List user's organizations
export async function GET() {
  const context = await getSessionContext()
  if (!context) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const organizations = await getUserOrganizations(context.userId)
  return NextResponse.json({ organizations })
}

// POST /api/organizations - Create new org (system admin only)
export async function POST(request: Request) {
  try {
    const context = await requireSystemAdmin()
    const { name, slug } = await request.json()

    if (!name || !slug) {
      return NextResponse.json(
        { error: "Name and slug are required" },
        { status: 400 }
      )
    }

    // Validate slug format
    if (!/^[a-z0-9-]+$/.test(slug)) {
      return NextResponse.json(
        { error: "Slug must be lowercase alphanumeric with hyphens only" },
        { status: 400 }
      )
    }

    const org = await createOrganization(name, slug, context.userId)
    return NextResponse.json({ organization: org }, { status: 201 })
  } catch (error) {
    if (error.message === "System admin access required") {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 })
    }
    throw error
  }
}

import { NextResponse } from "next/server"
import { getSessionContext, requireOrgAdmin } from "@/lib/session-context"
import { getOrganizationById, updateOrganization, deleteOrganization } from "@/lib/db-orgs"

// GET /api/organizations/[id]
export async function GET(
  request: Request,
  { params }: { params: { id: string } }
) {
  const context = await getSessionContext()
  if (!context) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const orgId = parseInt(params.id)

  // Verify user belongs to this org
  if (context.organizationId !== orgId) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const org = await getOrganizationById(orgId)
  if (!org) {
    return NextResponse.json({ error: "Not found" }, { status: 404 })
  }

  return NextResponse.json({ organization: org })
}

// PATCH /api/organizations/[id] - Update org (org admin only)
export async function PATCH(
  request: Request,
  { params }: { params: { id: string } }
) {
  const context = await requireOrgAdmin()
  const orgId = parseInt(params.id)

  if (context.organizationId !== orgId) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const updates = await request.json()
  const org = await updateOrganization(orgId, updates)

  return NextResponse.json({ organization: org })
}

// DELETE /api/organizations/[id] - Delete org (system admin only)
export async function DELETE(
  request: Request,
  { params }: { params: { id: string } }
) {
  const context = await requireSystemAdmin()
  const orgId = parseInt(params.id)

  await deleteOrganization(orgId)
  return NextResponse.json({ success: true })
}

import { NextResponse } from "next/server"
import { requireOrgAdmin } from "@/lib/session-context"
import {
  getOrganizationMembers,
  addOrganizationMember,
  createOrgInvite
} from "@/lib/db-orgs"
import { getUserByEmail } from "@/lib/db-users"

// GET /api/organizations/[id]/members
export async function GET(
  request: Request,
  { params }: { params: { id: string } }
) {
  const context = await requireOrgAdmin()
  const orgId = parseInt(params.id)

  if (context.organizationId !== orgId) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const members = await getOrganizationMembers(orgId)
  return NextResponse.json({ members })
}

// POST /api/organizations/[id]/members - Invite/add member
export async function POST(
  request: Request,
  { params }: { params: { id: string } }
) {
  const context = await requireOrgAdmin()
  const orgId = parseInt(params.id)

  if (context.organizationId !== orgId) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 })
  }

  const { email, role = "viewer" } = await request.json()

  if (!email) {
    return NextResponse.json({ error: "Email required" }, { status: 400 })
  }

  // Check if user already exists
  const existingUser = await getUserByEmail(email)

  if (existingUser) {
    // Add existing user to org
    const member = await addOrganizationMember(orgId, existingUser.id, role)
    return NextResponse.json({ member, status: "added" })
  } else {
    // Create invite for new user
    const invite = await createOrgInvite(orgId, email, role, context.userId)
    return NextResponse.json({ invite, status: "invited" })
  }
}

