// Update the checkUserAccess function to handle org assignment

export async function checkUserAccess(email: string): Promise<{
  hasAccess: boolean
  user?: DashboardUser
  isNewUser?: boolean
}> {
  const sql = getSql()

  // Check if user exists
  const existingUser = await getUserByEmail(email)
  if (existingUser) {
    return { hasAccess: true, user: existingUser }
  }

  // Check for invite
  const invite = await getInviteByEmail(email)
  if (!invite || invite.used) {
    return { hasAccess: false }
  }

  // Create user from invite
  const newUser = await createUserFromInvite(email, invite)

  return {
    hasAccess: true,
    user: newUser,
    isNewUser: true
  }
}

async function createUserFromInvite(
  email: string,
  invite: Invite
): Promise<DashboardUser> {
  const sql = getSql()

  // Determine which org to assign
  // If invite has org_id, use that; otherwise use Attorneyshare org
  const orgId = invite.org_id || (await getAttorneyshareOrgId())

  // Create the user
  const [user] = await sql`
    INSERT INTO dashboard_users (email, role, invited_by, default_org_id)
    VALUES (${email}, ${invite.role}, ${invite.invited_by}, ${orgId})
    RETURNING *
  `

  // Add user to organization as member
  await sql`
    INSERT INTO organization_members (organization_id, user_id, role)
    VALUES (${orgId}, ${user.id}, ${invite.role === 'admin' ? 'admin' : 'viewer'})
  `

  // Mark invite as used
  await markInviteAsUsed(invite.id)

  return user
}

async function getAttorneyshareOrgId(): Promise<number> {
  const sql = getSql()
  const [org] = await sql`
    SELECT id FROM organizations WHERE slug = 'attorneyshare' LIMIT 1
  `
  return org?.id || 1
}

