-- ===================================================== -- Migration 010: Row-Level Security for Multi-Tenancy -- =====================================================
-- Note: This requires the application to set a session variable -- with the current user's organization ID before queries. -- Alternative: Use Neon Auth's built-in user context.
-- 1. Enable RLS on test tables ALTER TABLE test_executions ENABLE ROW LEVEL SECURITY; ALTER TABLE test_results ENABLE ROW LEVEL SECURITY; ALTER TABLE test_artifacts ENABLE ROW LEVEL SECURITY; ALTER TABLE test_flakiness_history ENABLE ROW LEVEL SECURITY;
-- 2. Create policies for test_executions CREATE POLICY "Users can view their org's executions" ON test_executions FOR SELECT USING ( organization_id IN ( SELECT om.organization_id FROM organization_members om JOIN dashboard_users u ON u.id = om.user_id WHERE u.email = auth.email() -- Neon Auth function ) );
CREATE POLICY "Users can insert to their org" ON test_executions FOR INSERT WITH CHECK ( organization_id IN ( SELECT om.organization_id FROM organization_members om JOIN dashboard_users u ON u.id = om.user_id WHERE u.email = auth.email() ) );
-- 3. Create policies for test_results (through execution) CREATE POLICY "Users can view results through execution" ON test_results FOR SELECT USING ( execution_id IN ( SELECT id FROM test_executions WHERE organization_id IN ( SELECT om.organization_id FROM organization_members om JOIN dashboard_users u ON u.id = om.user_id WHERE u.email = auth.email() ) ) );
-- 4. Create policies for test_artifacts (through test_result -> execution) CREATE POLICY "Users can view artifacts through execution" ON test_artifacts FOR SELECT USING ( test_result_id IN ( SELECT tr.id FROM test_results tr JOIN test_executions te ON te.id = tr.execution_id WHERE te.organization_id IN ( SELECT om.organization_id FROM organization_members om JOIN dashboard_users u ON u.id = om.user_id WHERE u.email = auth.email() ) ) );
-- 5. Create policies for flakiness history CREATE POLICY "Users can view their org's flakiness" ON test_flakiness_history FOR SELECT USING ( organization_id IN ( SELECT om.organization_id FROM organization_members om JOIN dashboard_users u ON u.id = om.user_id WHERE u.email = auth.email() ) );
-- 6. Admin bypass policy (optional - for system admins) CREATE POLICY "Admins can view all" ON test_executions FOR ALL USING ( EXISTS ( SELECT 1 FROM dashboard_users WHERE email = auth.email() AND role = 'admin' ) );
-- Note: Similar admin policies needed for other tables
